def ladderLength(beginWord, endWord, wordList):
    if endWord not in wordList: return 0
    L = len(beginWord); m = collections.defaultdict(list)
    for w in wordList:
        for i in range(L): m[w[:i]+"*"+w[i+1:]].append(w)
    q, seen = collections.deque([(beginWord, 1)]), {beginWord}
    while q:
        w, d = q.popleft()
        for i in range(L):
            for n in m[w[:i]+"*"+w[i+1:]]:
                if n == endWord: return d+1
                if n not in seen: seen.add(n); q.append((n, d+1))
            m[w[:i]+"*"+w[i+1:]] = []
    return 0

